package org.eclipse.rdf4j.repository.http;

import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.TupleQuery;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.Repository;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.testsuite.repository.TupleQueryResultTest;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.BeforeAll;

public class HTTPTupleQueryResultTest extends TupleQueryResultTest {

	private static HTTPMemServer server;

	@BeforeAll
	public static void startServer() throws Exception {
		server = new HTTPMemServer();
		try {
			server.start();
		} catch (Exception e) {
			server.stop();
			throw e;
		}
	}

	@AfterAll
	public static void stopServer() throws Exception {
		server.stop();
	}

	@Override
	protected Repository newRepository() {
		return new HTTPRepository(HTTPMemServer.REPOSITORY_URL);
	}

	@Override
	public void testNotClosingResultThrowsException() {
		Repository repository = newRepository();
		TupleQueryResult result;
		try {
			try (RepositoryConnection connection = repository.getConnection()) {
				TupleQuery tupleQuery = connection.prepareTupleQuery(QueryLanguage.SPARQL, "select * where {?s ?p ?o}");
				result = tupleQuery.evaluate();
			}

			TupleQueryResult resultAfterConnectionClose = result;
			Assertions.assertDoesNotThrow(resultAfterConnectionClose::close);
		} finally {
			repository.shutDown();
		}
	}

}
